import { Account } from '@domain/account';
import {
  ActionPageAmountConfiguration,
  ActionPageAmountConfigurationFormValues,
  AmountPresetFrequency,
} from '@domain/action_pages/action_page_amount_configuration';
import { ActionPageAmountPreset } from '@domain/action_pages/action_page_amount_preset';
import { ActionPageDetailFormValues } from '@domain/actionPages';
import {
  ConfigurationOption,
  ConfigurationPanelProps,
} from '@pages/ActionPages/pages/ActionPagesBuilder/components/ConfigurationPanel';
import { useGetAccount } from '@state/accounts';
import { useCreateActionPageAmountConfiguration } from '@state/org/action_page_amount_configurations/mutations/useCreateActionPageAmountConfiguration';
import { useDeleteActionPageAmountConfiguration } from '@state/org/action_page_amount_configurations/mutations/useDeleteActionPageAmountConfiguration';
import { useUpdateActionPageAmountConfiguration } from '@state/org/action_page_amount_configurations/mutations/useUpdateActionPageAmountConfiguration';
import { useGetActionPageAmountConfiguration } from '@state/org/action_page_amount_configurations/queries/useGetActionPageAmountConfiguration';
import { useGetInfiniteActionPageAmountConfigurations } from '@state/org/action_page_amount_configurations/queries/useGetActionPageAmountConfigurations';
import { centsToDollars } from '@ui/utils/centsToDollars/centsToDollars';
import { omit } from '@utils';
import { isTempId } from '@utils/isTempId';
import { setValueRecursive } from '@utils/setValueRecursive';
import currency from 'currency.js';
import { parseISO, startOfDay } from 'date-fns';
import { zonedTimeToUtc } from 'date-fns-tz';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';
import { useConfigurationStore } from '../../../../contexts/ConfigurationContext';

const configurationIdKey = 'amountConfigurationId';
const key = 'amountConfiguration' as const;

export const toAmountConfigurationFormValues = (
  configuration: ActionPageAmountConfiguration
): ActionPageAmountConfigurationFormValues => {
  return {
    ...configuration,
    amountPresets: configuration?.amountPresets
      ? Object.keys(configuration?.amountPresets).reduce(
          (a, b) => {
            const presets = configuration.amountPresets![b as AmountPresetFrequency];

            if (presets) {
              return {
                ...a,
                [b]: presets.map((preset) => ({
                  ...preset,
                  amount: centsToDollars(preset.amount),
                })),
              };
            }

            return a;
          },
          {} as Record<AmountPresetFrequency, ActionPageAmountPreset[]>
        )
      : undefined,
    // have to ignore the timezone when parsing or else when viewing in other timezones it will shift the day
    futurePledgeDate: configuration.futurePledgeDate
      ? parseISO(configuration.futurePledgeDate.split('T')[0])
      : undefined,
    recurringMessage: configuration?.recurringMessage || '',
    transactionMaximum: centsToDollars(configuration?.transactionMaximum),
    transactionMinimum: centsToDollars(configuration?.transactionMinimum),
  };
};

const getDateInTimeZone = (date: Date, timeZone: string | undefined | null): string => {
  if (!timeZone) {
    return startOfDay(date).toISOString();
  }

  return zonedTimeToUtc(date, timeZone).toISOString();
};

export const toAmountConfigurationDetails = (
  configuration: ActionPageAmountConfigurationFormValues | undefined | null,
  account: Account | undefined
): ActionPageAmountConfiguration | undefined => {
  if (!configuration) {
    return undefined;
  }

  return {
    ...configuration,
    amountPresets: configuration?.amountPresets
      ? Object.keys(configuration?.amountPresets).reduce(
          (acc, nextPreset) => {
            const presets = configuration.amountPresets![nextPreset as AmountPresetFrequency];

            if (presets) {
              return {
                ...acc,
                [nextPreset]: presets.map((preset) => ({
                  ...preset,
                  amount: preset.amount ? currency(preset.amount).intValue : 0,
                })),
              };
            }

            return acc;
          },
          {} as Record<AmountPresetFrequency, ActionPageAmountPreset[]>
        )
      : undefined,
    futurePledgeDate: configuration.futurePledgeDate
      ? getDateInTimeZone(configuration.futurePledgeDate, account?.timeZone)
      : '',
    transactionMaximum: configuration?.transactionMaximum
      ? currency(configuration?.transactionMaximum).intValue
      : undefined,
    transactionMinimum: configuration?.transactionMinimum
      ? currency(configuration?.transactionMinimum).intValue
      : undefined,
  };
};

export const useAmountConfigurations = (): ConfigurationPanelProps & { isLoading: boolean } => {
  const { getValues, setValue } = useFormContext<ActionPageDetailFormValues>();
  const [bulkUpdateConfigurationId, stopEditing, onConfigurationError] = useConfigurationStore(
    (state) => [state.bulkUpdateConfigurationId, state.onCancel, state.onConfigurationError]
  );
  const configurationId = useWatch({ name: `${key}.id` });
  const { mutateAsync: deleteConfiguration } = useDeleteActionPageAmountConfiguration();
  const { mutateAsync: deleteConfigurationSilent } = useDeleteActionPageAmountConfiguration({
    showToast: false,
  });
  const [searchTerm, onItemSearch] = useState('');
  const { currentAccount } = useGetAccount();

  const { data: selected } = useGetActionPageAmountConfiguration({
    configurationId,
  });

  const { data: bulkUpdateConfiguration } = useGetActionPageAmountConfiguration({
    configurationId: bulkUpdateConfigurationId,
  });

  const bulkUpdateConfigurationOption: ConfigurationOption | undefined = useMemo(
    () =>
      bulkUpdateConfiguration
        ? {
            ...bulkUpdateConfiguration,
            label: bulkUpdateConfiguration.name || bulkUpdateConfiguration.id || '',
            name: bulkUpdateConfiguration.name || bulkUpdateConfiguration.id || '',
          }
        : undefined,
    [bulkUpdateConfiguration]
  );

  const { configurations, fetchMoreConfigurations, hasMoreConfigurations, isLoading } =
    useGetInfiniteActionPageAmountConfigurations({ searchTerm });

  const {
    error: creationError,
    isLoading: isCreatingConfiguration,
    mutateAsync: createConfiguration,
  } = useCreateActionPageAmountConfiguration({ showToast: false });

  const {
    error: updateError,
    isLoading: isUpdatingConfiguration,
    mutateAsync: updateConfiguration,
  } = useUpdateActionPageAmountConfiguration({ showToast: false });

  const options = useMemo<ConfigurationOption[]>(() => {
    const opts = (configurations?.filter((config) => !config.name?.includes('_internal')) ?? [])
      .filter((preset) => preset.id !== selected?.id)
      .map((preset) => ({
        actionPageCount: preset.actionPageCount,
        canDelete: !preset.attachedToActionPage && preset.id !== configurationId,
        id: preset.id,
        label: preset.name ?? preset.id ?? '',
        name: preset.name ?? preset.id ?? '',
      }));

    if (selected && !isTempId(selected.name)) {
      return [
        {
          actionPageCount: selected.actionPageCount,
          canDelete: !selected.attachedToActionPage && selected.id !== configurationId,
          id: selected.id,
          label: selected.name ?? selected.id ?? '',
          name: selected.name ?? selected.id ?? '',
        },
        ...opts,
      ];
    }

    return opts;
  }, [configurationId, configurations, selected]);

  const onCreate = useCallback(async () => {
    const newConfiguration = omit(toAmountConfigurationDetails(getValues(key), currentAccount), [
      'actionPageCount',
      'attachedToActionPage',
      'updatedAt',
      'createdAt',
      'accountId',
      'id',
      'default',
    ]);

    const configuration = await createConfiguration(newConfiguration);

    if (configuration) {
      setValue(configurationIdKey, configuration.id);

