  templateGroups?: TemplateGroup[];
  templates?: Template[];
};

export const formId = 'action-pages-builder-form';

const getPanelState = (basePath: string, pathname: string, routes: RouteOption[]) => {
  const activeIndex = routes.findIndex(({ path }) => matchPath(`${basePath}/${path}/*`, pathname));

  if (activeIndex !== 0) {
    return [1, activeIndex, 0];
  }

  return [0, 0, 0];
};

export const ActionPagesBuilder = ({
  actionPage,
  basePath,
  customFields,
  featuredTemplate,
  onApplyFilters,
  onClearFilters,
  onUpdateActionPage,
  routes,
  showTemplates,
  templateGroups,
  templates,
}: ActionPagesBuilderProps) => {
  const { currentAccount, keepQueryParamNavigate, navigate, pathname } =
    useActionPagesBuilderNavigation();
  const accountId = currentAccount?.id;
  const containerRef = useRef<HTMLDivElement>(null);
  const searchParams = useQueryParam();
  const { t } = useTranslation(['actionPagesBuilder', 'actionPageSettings', 'actionPageWorkflows']);

  const [editing, serverError, onPostPublish, onPrePublish] = useConfigurationStore((state) => [
    state.editing,
    state.error,
    state.onPostPublish,
    state.onPrePublish,
  ]);

  const schema: ActionPagesBuilderSchema = useMemo(
    () => actionPagesBuilderSchema(t, { customFields, editingConfiguration: editing?.key }),
    [t, customFields, editing?.key]
  );

  const isOnNoSubRoute = useMatch('/accounts/:accountId/action_pages/:actionPageId/edit');
  const { changeQueryFilter: changeTemplateQueryFilter, queryFilters: templateQueryFilters } =
    useQueryFilters<TemplateQueryFilter>('q', 'type', 'category', 'layout', 'onlyFavorites');

  /** currentSubPage is used within the setOption function for correctly animating between sub panels */
  const [[currentPage, currentSubPage, direction], setCurrentPage] = useState(
    getPanelState(basePath, pathname, routes)
  );

  // Prevent enter key in any form input from submitting the form
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.keyCode === 13 && (e.target as HTMLElement)?.tagName !== 'TEXTAREA') {
        e.preventDefault();
        return false;
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  /** Callback to correctly animate panels */
  const setOption = (newOption: number) => {
    if (showTemplates && newOption === 0) {
      setCurrentPage(([page]) => [0, 0, newOption - page]);
    } else {
      setCurrentPage(([_, subPage]) => [1, newOption, newOption - subPage]);
    }

    navigate(routes[newOption].path as string, { replace: true });
  };

  /** go back to the main action pages index */
  const onBack = () => {
    keepQueryParamNavigate(
      generatePath('/accounts/:accountId/action_pages', {
        accountId: accountId as string,
      })
    );
  };

  const onSubmit = useCallback(
    async (
      _values: ActionPageDetailFormValues,
      { getValues, reset }: UseFormReturn<ActionPageDetailFormValues, object>
    ) => {
      await onPrePublish?.();

      if (onUpdateActionPage) {
        const updates = getValues();

        const request = mapActionPageDetailFormValuesToDetails(
          JSON.parse(JSON.stringify(updates)) as ActionPageDetailFormValues
        );

        const apDetails = await onUpdateActionPage({
          ...request,
          pageType: updates.pageType,
        });

        await onPostPublish?.();

        // navigate to new url once returned
        navigate(
          `/${pathname.replace(`/new/`, `/${apDetails.id}/`)}?${searchParams.toString()}`.replace(
            /\/\//g,
            '/'
          ),
          { replace: true, state: null }
        );

        reset({
          // Keep all the configurations the same
          ...Object.fromEntries(
            Object.entries(updates).filter(([key]) => key.endsWith('Configuration'))
          ),
          // Set the new values for the rest of the AP from the server response
          ...mapActionPageDetailsToFormValues(apDetails, updates.customFields),
        });
      }
    },
    [navigate, onPostPublish, onPrePublish, onUpdateActionPage, pathname, searchParams]
  );

  if (isOnNoSubRoute) {
    return <Navigate to={`${routes[0].path as string}?${searchParams.toString()}`} />;
  }

  // if no account or no action page, show a loading indicator
  if (!currentAccount?.id || !actionPage) {
    return (
      <Flex height="full" width="full">
        <Loading />
      </Flex>
    );
  }

