import {
  ActionPageContentBlock,
  ActionPageContentBlockFormValues,
  ActionPageDetailFormValues,
  ActionPageDetails,
} from '@domain/actionPages';
import { ICustomField } from '@domain/customField';
import { centsToDollars } from '@ui/utils/centsToDollars';
import { parseDate } from '@ui/utils/parseDate';
import { numberToPx } from '@utils/numberToPx';
import { pxToNumber } from '@utils/pxToNumber';
import currency from 'currency.js';
import { formatISO } from 'date-fns';
import getEmbedUrl from '../components/Preview/EditorBlockPreview/Video/getEmbedUrl';

export const mapActionPageDetailsToFormValues = (
  actionPage: ActionPageDetails,
  customFields: ICustomField[] = []
): ActionPageDetailFormValues => {
  let pageDictionary = {};

  try {
    pageDictionary = actionPage.pageDictionary ? JSON.parse(actionPage.pageDictionary) : {};
  } catch (_err) {
    pageDictionary = {};
  }

  return {
    ...actionPage,
    backgroundImagePosition: actionPage.backgroundImagePosition || 'fill',
    content: actionPage.content
      ?.filter((block) => block?.type)
      ?.map((block) => {
        switch (block.type) {
          case 'image':
            return {
              content: {
                ...block.content,
                align: 'center',
                height: pxToNumber(block.content.height),
                width: pxToNumber(block.content.width),
              },
              type: block.type,
            };
          case 'divider':
            return {
              content: {
                ...block.content,
                backgroundColor: block.content.backgroundColor || '#FFFFFF',
                borderWidth: pxToNumber(block.content.borderWidth),
                paddingBottom: pxToNumber(block.content.paddingBottom),
                paddingTop: pxToNumber(block.content.paddingTop),
              },
              type: block.type,
            };
          case 'timer':
            return {
              content: {
                ...block.content,
                countdownSeconds: (block.content.countdownSeconds ?? 0) / 60 || 0,
                deadline: block.content.deadline ? parseDate(block.content.deadline) : undefined,
                displayBannerTimer: block.content.displayBannerTimer || false,
                displayFormTimer: block.content.displayFormTimer || false,
              },
              type: block.type,
            };
          case 'text':
            return {
              content: {
                ...block.content,
                numOfColumns: block.content.hasSecondColumn ? '2' : '1',
              },
              type: block.type,
            };
          default:
            return block;
        }
      }) as ActionPageContentBlockFormValues[],
    customFields,
    // We are initializing employed to true here to force the
    // employment field to be selected as Yes by default in the editor
    // @ts-ignore
    employed: true,
    goaaMinimumAmount: centsToDollars(actionPage?.goaaMinimumAmount),
    goal: centsToDollars(actionPage.goal),
    headerImagePosition: actionPage.headerImagePosition || 'center',
    headerTitleText:
      new DOMParser().parseFromString(actionPage.headerTitleText || '', 'text/html').documentElement
        .textContent ?? '',
    pageDictionary,
  };
};

// Subset of fields are supported for update
// https://github.com/anedot/anedot/blob/master/spec/integration/api/org/v3/action_pages_spec.rb#L384
export const mapActionPageDetailFormValuesToDetails = (
  actionPage: ActionPageDetailFormValues
): ActionPageDetails => {
  return {
    amountConfigurationId: actionPage.amountConfigurationId || actionPage.amountConfiguration?.id,
    backgroundImageId: actionPage.backgroundImageId,
    backgroundImagePosition: actionPage.backgroundImagePosition,
    billingAgreementIds: actionPage?.billingAgreementIds,
    confirmationConfigurationId:
      actionPage.confirmationConfiguration?.id || actionPage.confirmationConfigurationId,
    content: actionPage.content
      ?.filter((block) => !(block?.type === 'image' && !block?.content?.image) && block?.type)
      .map((block) => {
        switch (block.type) {
          case 'image':
            return {
              content: {
                caption: block.content?.caption || null,
                height: numberToPx(block.content.height) || null,
                image: {
                  id: block.content?.image?.id,
                },
                width: numberToPx(block.content.width) || null,
              },
              type: block.type,
            };
          case 'divider':
            return {
              content: {
                ...block.content,
                borderWidth: numberToPx(block.content.borderWidth) || '',
                paddingBottom: numberToPx(block.content.paddingBottom) || '',
                paddingTop: numberToPx(block.content.paddingTop) || '',
              },
              type: block.type,
            };
          case 'timer':
            return {
              content: {
                ...block.content,
                countdownSeconds: Number(block.content.countdownSeconds) * 60 || 0,
                deadline: block.content.deadline
                  ? formatISO(new Date(block.content.deadline))
                  : undefined,
              },
              type: block.type,
            };
          case 'text':
            return {
              content: {
                hasSecondColumn: block.content.numOfColumns === '2',
                secondColumnText: block.content.secondColumnText,
                text: block.content.text,
              },
              type: block.type,
            };
          case 'video': {
            const embedUrl = getEmbedUrl(block.content.url);

            return {
              content: {
                ...block.content,
                url:
                  embedUrl && embedUrl.indexOf('href=') > -1
                    ? embedUrl.split('href=')[1]
                    : embedUrl || '',
              },
              type: block.type,
            };
          }
          default:
            return block;
        }
      }) as ActionPageContentBlock[],
    defaultSourceCode: actionPage.defaultSourceCode,
    designConfigurationId: actionPage.designConfigurationId || actionPage.designConfiguration?.id,
    exitIntentBody: actionPage.exitIntentBody,
    exitIntentImageId: actionPage.exitIntentImageId,
    exitIntentTitle: actionPage.exitIntentTitle,
    facebookSocialShareDescription: actionPage.facebookSocialShareDescription,
    facebookSocialShareImageId: actionPage.facebookSocialShareImageId,
