    favIconId: actionPage.favIconId,
    fieldConfigurationId: actionPage.fieldConfiguration?.id,
    footerDisclaimer: actionPage.footerDisclaimer,
    footerShowAccountName: actionPage.footerShowAccountName,
    formAlignment: actionPage.formAlignment,
    formLayout: actionPage.formLayout,
    formStyle: actionPage.formStyle,
    fundConfigurationId: actionPage.fundConfigurationId || actionPage.fundConfiguration?.id,
    generalConfigurationId: actionPage.generalConfiguration?.id,
    goaaEnabled: actionPage.goaaEnabled,
    goaaForceSelection: actionPage.goaaForceSelection,
    goaaMinimumAmount: actionPage?.goaaMinimumAmount
      ? currency(actionPage?.goaaMinimumAmount).intValue
      : undefined,
    goal: actionPage.goal ? currency(actionPage.goal).intValue : 0,
    headerImageId: actionPage.headerImageId,
    headerImagePosition: actionPage.headerImagePosition,
    headerTitleAlignment: actionPage.headerTitleAlignment,
    headerTitleText: actionPage.headerTitleText,
    id: actionPage.id,
    messageId: actionPage.messageId,
