type UseCreateClonedPresetsProps = {
  cloneFrom?: string | null;
  source?: ActionPageDetails;
};

// create new cloned temp configs for cloned AP if source AP used temp configs
export const useCreateClonedPresets = ({ cloneFrom, source }: UseCreateClonedPresetsProps) => {
  const [newClonedAmountConfig, setNewClonedAmountConfig] =
    useState<ActionPageAmountConfiguration>();
  const [newClonedDesignConfig, setNewClonedDesignConfig] =
    useState<ActionPageDesignConfiguration>();
  const [newClonedFieldConfig, setNewClonedFieldConfig] = useState<ActionPageFieldConfiguration>();
  const [newClonedGeneralConfig, setNewClonedGeneralConfig] =
    useState<ActionPageGeneralConfiguration>();
  const [newClonedPaymentConfig, setNewClonedPaymentConfig] =
    useState<ActionPagePaymentConfiguration>();
  const [newClonedFundConfig, setNewClonedFundConfig] = useState<ActionPageFundConfiguration>();
  const [newClonedConfirmationConfig, setNewClonedConfirmationConfig] =
    useState<ActionPageConfirmationConfiguration>();
  const [newClonedUpgradeConfig, setNewClonedUpgradeConfig] =
    useState<ActionPageUpgradeConfiguration>();

  const { data: amountConfigurationResponse, isLoading: isLoadingAmountConfiguration } =
    useGetActionPageAmountConfiguration({
      configurationId: source?.amountConfigurationId,
    });

  const { isLoading: isCreatingAmountConfiguration, mutateAsync: createAmountConfiguration } =
    useCreateActionPageAmountConfiguration();

  useEffect(() => {
    if (cloneFrom && !isLoadingAmountConfiguration && isTempId(amountConfigurationResponse?.name)) {
      createAmountConfiguration({
        ...amountConfigurationResponse,
        default: false,
        name: undefined,
        amountPresetsOther: amountConfigurationResponse?.amountPresetsOther || false,
      }).then((config) => {
        setNewClonedAmountConfig(config);
      });
    }
  }, [
    amountConfigurationResponse,
    cloneFrom,
    createAmountConfiguration,
    isLoadingAmountConfiguration,
  ]);

  const { data: designConfigurationsResponse, isLoading: isLoadingDesignConfiguration } =
